__CPROVER_ensures(__CPROVER_was_freed(__CPROVER_old(lmc->length)))
__CPROVER_ensures(__CPROVER_was_freed(__CPROVER_old(lmc->dist)))
__CPROVER_ensures(__CPROVER_was_freed(__CPROVER_old(lmc->sublen)))
{
    free(lmc->length);
    free(lmc->dist);
    free(lmc->sublen);
